  const renderMarkdown = (text) => {
    try {
      // Known abbreviations that should NOT trigger line breaks
      const abbrevPattern = /\b(Mr|Mrs|Ms|Dr|Prof|Sr|Jr|St|vs|etc|approx|dept|est|govt|inc|ltd|co|corp|assn|ave|blvd|rd|st|sq|mt|ft|hr|min|sec|Jan|Feb|Mar|Apr|Jun|Jul|Aug|Sep|Oct|Nov|Dec|eg|ie)\. /g;

      // Temporarily protect abbreviations, then insert \n\n after real sentence endings
      const abbrMap = {};
      let counter = 0;

      // Markdown the text:
      // 1. Split run-on LLM paragraphs (one long line with periods) into actual lines
      // 2. Preserve abbreviations so "Dr. Smith" doesn't become "Dr.\n\nSmith"
      let formatted = (text || "")
        // Protect abbreviations with unique placeholders
        .replace(abbrevPattern, (m) => {
          const key = "\x00AB" + (counter++) + "\x00";
          abbrMap[key] = m;
          return key;
        })
        // Sentence break: .!? + space + capitalized word (any length) or number/quote
        .replace(/([.!?])\s+(?=[A-Z][a-z]{0,}|[0-9"'\[(])/g, "$1\n\n")
        // Handle sentence endings followed by bullet/list markers
        .replace(/([.!?])\s+(?=[-*•])/g, "$1\n\n")
        // Colons introducing explanations (after lowercase letter before capital)
        .replace(/([a-z]):\s+(?=[A-Z"'\[])/g, "$1:\n\n")
        // Restore abbreviations
        .replace(/\x00AB\d+\x00/g, (m) => abbrMap[m] || m)
        // Clean up excessive newlines
        .replace(/\n{3,}/g, "\n\n");

      return { __html: marked.parse(formatted, { breaks: true }) };
    } catch (e) {
