  voiceState,
  onVoiceStateToggle,
  onToggleListening,
  isListening,
  onSubmit,
  onStop,
  inputHistoryRef,
  inputHistoryIndexRef,

  // Empty state
  showEmptyState,
}) {
  return (
    <div
      style={{
        flex: 1,
        display: 'flex',
        flexDirection: 'column',
        padding: 'var(--space-5)',
        overflow: 'hidden',
      }}
    >
      {/* ── HITL Approval Banner ── */}
      <ApprovalBanner
        approvalRequest={approvalRequest}
        onApprove={(decision) => onApprove(decision !== undefined ? decision : true)}
        onDeny={() => onDeny(approvalRequest?.type === 'edit_permission' ? 'deny' : false)}
      />

      {/* ── Mode Badge ── */}
      {sessionMode && !showModePrompt && (
        <ModeBadge sessionMode={sessionMode} />
      )}

      {/* ── Mode Prompt ── */}
      {showModePrompt && <ModePrompt onSetMode={onSetSessionMode} />}

      {/* ── Chat Messages ── */}
      <div
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          position: 'relative',
          maxWidth: '900px',
          margin: '0 auto',
          width: '100%',
          minHeight: 0,
          overflowY: 'auto',
          paddingBottom: 'var(--space-5)',
        }}
      >
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--space-4)',
