            padding: '4px',
          }}
        >
          {MODES.map((m) => {
            const isActive = (sessionMode || '') === m.id;
            return (
              <button
                key={m.id}
                onClick={() => {
                  onSetSessionMode(m.id);
                  setOpen(false);
                }}
                className="interactive-base focus-ring"
                style={{
